func (pt pageTree) Parent() page.Page {
	if pt.p.IsHome() {
		return nil
	}

	dir := pt.p.m.pathInfo.ContainerDir()

	if dir == "" {
		return pt.p.s.home
	}

	for {
		_, n := pt.p.s.pageMap.treePages.LongestPrefix(dir, true, nil)
		if n == nil {
			return pt.p.s.home
		}
		if pt.p.m.bundled || n.isContentNodeBranch() {
			return n.(page.Page)
		}
		dir = paths.Dir(dir)
	}
}
